<?php
namespace App\Services\Provider\Drivers;use App\Models\TopupOrder;use App\Models\Provider;use App\Services\Provider\Contracts\ProviderDriver;use Illuminate\Support\Facades\Http;class GenericHttpProviderDriver implements ProviderDriver{public function __construct(private Provider $provider){}public function submitOrder(TopupOrder $order):array{if($this->provider->driver==='mock'||env('TOPUP_PROVIDER_MODE','mock')==='mock'){return ['success'=>true,'provider_order_id'=>'MOCK-'.$order->order_no,'message'=>'Top-up completed successfully.','raw'=>['mode'=>'mock']];}$headers=['Accept'=>'application/json'];if($this->provider->auth_type==='bearer'&&$this->provider->api_key){$headers['Authorization']='Bearer '.$this->provider->api_key;}$payload=['reference'=>$order->order_no,'product_code'=>$order->package->provider_product_id,'player_id'=>$order->player_id,'server_id'=>$order->server_id,'amount'=>$order->amount_minor,'currency'=>$order->currency_code];$response=Http::withHeaders($headers)->timeout($this->provider->timeout_seconds?:30)->retry($this->provider->retry_count?:0,300,throw:false)->post(rtrim($this->provider->base_url,'/').'/'.ltrim($this->provider->submit_endpoint?:'/orders','/'),$payload);if(!$response->successful()){return ['success'=>false,'message'=>'Provider API failed.','raw'=>$response->json()?:$response->body()];}$data=$response->json();return ['success'=>(bool)($data['success']??true),'provider_order_id'=>$data['order_id']??$data['provider_order_id']??null,'message'=>$data['message']??'Order submitted successfully.','raw'=>$data];}public function checkStatus(TopupOrder $order):array{if($this->provider->driver==='mock'){return ['status'=>'completed'];}$response=Http::get(rtrim($this->provider->base_url,'/').'/'.ltrim($this->provider->status_endpoint?:'/orders/status','/'),['reference'=>$order->provider_order_id]);return $response->json()?:[];}}
